@spec vm_temper_entry_spec  src=tests/specs/vm_temper_entry_spec.lua  loc=136  sha=fdb66b0  cases=3
@exercises trackerView (h.vm), editCursor (h.ec), tuning (tuning), commandManager (h.cmgr)
@surface   vm:setGridSize, ec:setPos, vm:editEvent, tuning.midiToStep, vm:noteProjection, cmgr:invoke
@harness   mk{seed.notes}

# Intent
  Wired entry under a temperament: drives the real tv:editEvent path
  (not a re-implementation) so the pitch/octave snapping it performs is
  the production wiring. The octave column edits the temper's period-
  cycle octave, keeping the scale step, and rejects octaves a note
  cannot sit on exactly. See docs/tuning.md for the coordinate model.

# Helpers
  @fn mk(harness)  @ 18-28
  @fn lane1(h)  @ 30-34
  @fn pitchStops(col)  @ 38-45
      -- The pitch part spans two cursor stops (note letter, octave digit);
      -- discover them so the test is independent of cellWidth.

# Cases
  @case 'octave column keeps the scale step and sets the period-cycle octave'  [harness]  @ 49-77
  @case 'octave column rejects an octave the note cannot sit on exactly'  [harness]  @ 81-103
  @case 'pitch nudge keeps a note in the addressable range (refuses past the ceiling)'  [harness]  @ 107-134

# Uses (outbound edges)
  @use call trackerView.setGridSize  @ 26
  @use call editCursor.setPos  @ 56,65,87,96,113,119
  @use call trackerView.editEvent  @ 57,66,88,97,114
  @use call tuning.midiToStep  @ 61,70
  @use call trackerView.noteProjection  @ 75
  @use call commandManager.invoke  @ 120,130
